/**
 * Avoid a name collision between PDF.js' pre-bundled output and the module
 * wrapper generated by Next.js' Webpack development build.
 */
module.exports = function pdfJsDistLoader(source) {
  this.cacheable();

  return source.replace(
    /\b__webpack_exports__\b/g,
    "__pdfjs_dist_webpack_exports__",
  );
};
